Steps to reproduce:

# mdconfig -s1g
# newfs /dev/md0
# mount /dev/md0 /mnt
# cp loop /mnt
# /mnt/loop

In another terminal:

# umount -f /mnt

loop.c:

#include <sys/mman.h>
#include <err.h>
#include <stdio.h>
#include <unistd.h>

int
main(void)
{
        int error;

        error = mlockall(MCL_CURRENT | MCL_FUTURE);
        if (error != 0)
                err(1, "mlockall");

        for (;;) {
                fprintf(stderr, ".");
                sleep(1);
        }
}
